1	// COR24 APL Interpreter -- Tokenizer
2	// Lexes input line into token array for the parser.
3	
4	#pragma once
5	
6	// Token types
7	#define TOK_EOL     0   // end of line
8	#define TOK_NUM     1   // integer literal (value in tok_val)
9	#define TOK_IDENT   2   // user identifier (uppercase, pos in tok_val)
10	#define TOK_PLUS    3   // +
11	#define TOK_MINUS   4   // - (parser decides monadic vs dyadic)
12	#define TOK_STAR    5   // *
13	#define TOK_SLASH   6   // /
14	#define TOK_LPAREN  7   // (
15	#define TOK_RPAREN  8   // )
16	#define TOK_ASSIGN  9   // <-
17	#define TOK_RES    10   // reserved word (ID in tok_val)
18	#define TOK_QUAD   11   // quad ([] — bare quad for I/O)
19	#define TOK_QLED   12   // qled — LED D2 hardware I/O
20	#define TOK_QSW    13   // qsw — switch S2 hardware I/O (read-only)
21	#define TOK_QSVO   14   // qsvo — shared variable offer (□SVO)
22	#define TOK_LBRAK  15   // [ (bracket index open)
23	#define TOK_RBRAK  16   // ] (bracket index close)
24	#define TOK_GOTO   17   // goto — branch (→)
25	#define TOK_STRING 18   // string literal 'ABC' (pos of first char in tok_val)
26	#define TOK_EQ     19   // =
27	#define TOK_NE     20   // !=
28	#define TOK_LT     21   // <
29	#define TOK_GT     22   // >
30	#define TOK_LE     23   // <=
31	#define TOK_GE     24   // >=
32	#define TOK_CEIL   25   // ceil (max) — internal only, used in reduce nodes
33	#define TOK_FLOOR  26   // floor (min) — internal only, used in reduce nodes
34	
35	// Reserved word IDs
36	#define RES_RHO     0
37	#define RES_IOTA    1
38	#define RES_TAKE    2
39	#define RES_DROP    3
40	#define RES_REV     4
41	#define RES_CAT     5
42	#define RES_AND     6
43	#define RES_OR      7
44	#define RES_NOT     8
45	#define RES_CEIL    9
46	#define RES_FLOOR  10
47	#define RES_COMPRESS 11
48	#define RES_PICK    12
49	
50	#define TOK_MAX    64   // max tokens per line
51	
52	// Token storage (parallel arrays)
53	int tok_type[TOK_MAX];  // token type
54	int tok_val[TOK_MAX];   // numeric value or reserved word ID
55	int tok_pos[TOK_MAX];   // start position in source line
56	int tok_count;           // number of tokens produced
57	
58	// ---- String helpers ----
59	
60	// Compare a substring of src starting at pos against a NUL-terminated word.
61	// Returns 1 if match, 0 otherwise.
62	int str_match(char *src, int pos, char *word) {
63	    int i = 0;
64	    while (word[i]) {
65	        if (src[pos + i] != word[i]) return 0;
66	        i++;
67	    }
68	    return i;  // return length of match (0 = no match since word is non-empty)
69	}
70	
71	// Check if character is a lowercase letter (a-z)
72	int is_lower(int ch) {
73	    return ch >= 97 && ch <= 122;
74	}
75	
76	// Check if character is an uppercase letter (A-Z)
77	int is_upper(int ch) {
78	    return ch >= 65 && ch <= 90;
79	}
80	
81	// Check if character is a digit (0-9)
82	int is_digit(int ch) {
83	    return ch >= 48 && ch <= 57;
84	}
85	
86	// Check if character is alphanumeric or underscore
87	int is_alnum(int ch) {
88	    return is_lower(ch) || is_upper(ch) || is_digit(ch);
89	}
90	
91	// ---- Reserved word lookup ----
92	// Returns reserved word ID if the lowercase word starting at pos matches,
93	// or -1 if not a reserved word. Sets *end to position past the word.
94	int lookup_reserved(char *src, int pos, int *end) {
95	    int len;
96	
97	    len = str_match(src, pos, "rho");
98	    if (len == 3 && !is_alnum(src[pos + 3])) { *end = pos + 3; return RES_RHO; }
99	
100	    len = str_match(src, pos, "iota");
101	    if (len == 4 && !is_alnum(src[pos + 4])) { *end = pos + 4; return RES_IOTA; }
102	
103	    len = str_match(src, pos, "take");
104	    if (len == 4 && !is_alnum(src[pos + 4])) { *end = pos + 4; return RES_TAKE; }
105	
106	    len = str_match(src, pos, "drop");
107	    if (len == 4 && !is_alnum(src[pos + 4])) { *end = pos + 4; return RES_DROP; }
108	
109	    len = str_match(src, pos, "rev");
110	    if (len == 3 && !is_alnum(src[pos + 3])) { *end = pos + 3; return RES_REV; }
111	
112	    len = str_match(src, pos, "cat");
113	    if (len == 3 && !is_alnum(src[pos + 3])) { *end = pos + 3; return RES_CAT; }
114	
115	    len = str_match(src, pos, "and");
116	    if (len == 3 && !is_alnum(src[pos + 3])) { *end = pos + 3; return RES_AND; }
117	
118	    len = str_match(src, pos, "or");
119	    if (len == 2 && !is_alnum(src[pos + 2])) { *end = pos + 2; return RES_OR; }
120	
121	    len = str_match(src, pos, "not");
122	    if (len == 3 && !is_alnum(src[pos + 3])) { *end = pos + 3; return RES_NOT; }
123	
124	    len = str_match(src, pos, "ceil");
125	    if (len == 4 && !is_alnum(src[pos + 4])) { *end = pos + 4; return RES_CEIL; }
126	
127	    len = str_match(src, pos, "floor");
128	    if (len == 5 && !is_alnum(src[pos + 5])) { *end = pos + 5; return RES_FLOOR; }
129	
130	    len = str_match(src, pos, "compress");
131	    if (len == 8 && !is_alnum(src[pos + 8])) { *end = pos + 8; return RES_COMPRESS; }
132	
133	    len = str_match(src, pos, "pick");
134	    if (len == 4 && !is_alnum(src[pos + 4])) { *end = pos + 4; return RES_PICK; }
135	
136	    return -1;
137	}
138	
139	// ---- Tokenizer ----
140	// Tokenize input line into tok_type/tok_val/tok_pos arrays.
141	// Returns number of tokens (also stored in tok_count).
142	// On error, returns -1 (unrecognized character).
143	int tokenize(char *line) {
144	    int i = 0;
145	    int t = 0;
146	
147	    while (line[i] && t < TOK_MAX - 1) {
148	        // Skip whitespace
149	        if (line[i] == 32) {
150	            i++;
151	            continue;
152	        }
153	
154	        // Number: digits, or underscore followed by digit (APL negative)
155	        if (is_digit(line[i]) || (line[i] == 95 && is_digit(line[i + 1]))) {
156	            tok_type[t] = TOK_NUM;
157	            tok_pos[t] = i;
158	            int end;
159	            tok_val[t] = parse_int(line, i, &end);
160	            i = end;
161	            t++;
162	            continue;
163	        }
164	
165	        // Lowercase letter: quad variables, reserved word, or unknown
166	        if (is_lower(line[i])) {
167	            // Check for quad variables first
168	            int len;
169	            len = str_match(line, i, "qled");
170	            if (len == 4 && !is_alnum(line[i + 4])) {
171	                tok_type[t] = TOK_QLED;
172	                tok_pos[t] = i;
173	                tok_val[t] = 0;
174	                t++;
175	                i = i + 4;
176	                continue;
177	            }
178	
179	            len = str_match(line, i, "qsw");
180	            if (len == 3 && !is_alnum(line[i + 3])) {
181	                tok_type[t] = TOK_QSW;
182	                tok_pos[t] = i;
183	                tok_val[t] = 0;
184	                t++;
185	                i = i + 3;
186	                continue;
187	            }
188	
189	            len = str_match(line, i, "qsvo");
190	            if (len == 4 && !is_alnum(line[i + 4])) {
191	                tok_type[t] = TOK_QSVO;
192	                tok_pos[t] = i;
193	                tok_val[t] = 0;
194	                t++;
195	                i = i + 4;
196	                continue;
197	            }
198	
199	            len = str_match(line, i, "goto");
200	            if (len == 4 && !is_alnum(line[i + 4])) {
201	                tok_type[t] = TOK_GOTO;
202	                tok_pos[t] = i;
203	                tok_val[t] = 0;
204	                t++;
205	                i = i + 4;
206	                continue;
207	            }
208	
209	            int end;
210	            int res = lookup_reserved(line, i, &end);
211	            if (res >= 0) {
212	                tok_type[t] = TOK_RES;
213	                tok_val[t] = res;
214	                tok_pos[t] = i;
215	                i = end;
216	                t++;
217	                continue;
218	            }
219	            // Unknown lowercase word -- error
220	            return -1;
221	        }
222	
223	        // String literal: 'ABC' (single-quoted, for qsvo left argument)
224	        if (line[i] == 39) {
225	            // 39 = single quote
226	            i++;
227	            tok_type[t] = TOK_STRING;
228	            tok_pos[t] = i;  // position of first char
229	            tok_val[t] = i;  // store start of string content
230	            while (line[i] && line[i] != 39) i++;
231	            if (line[i] != 39) return -1;  // unterminated string
232	            i++;  // skip closing quote
