1	// COR24 APL Interpreter -- Parser
2	// Right-to-left recursive descent with vector literal stranding.
3	// APL: all operators equal precedence, right-associative.
4	// 2 + 3 * 4  ->  2 + (3 * 4)  ->  14
5	// 1 2 3      ->  3-element vector (adjacent numbers strand)
6	
7	#pragma once
8	
9	// AST node types
10	#define NODE_NUM    0   // integer literal (val = value)
11	#define NODE_BINOP  1   // binary op (val = operator tok type)
12	#define NODE_NEG    2   // monadic negate (right = operand)
13	#define NODE_IDENT  3   // variable reference (val = symbol index)
14	#define NODE_ASSIGN 4   // assignment (val = symbol index, right = expr)
15	#define NODE_VEC    5   // vector literal (val = heap array index)
16	#define NODE_MONAD  6   // monadic primitive (val = RES_xxx, right = operand)
17	#define NODE_DYAD   7   // dyadic primitive (val = RES_xxx, left/right = args)
18	#define NODE_REDUCE 8   // reduce operator (val = op tok type, right = operand)
19	#define NODE_QOUT   9   // quad output (right = expr to print)
20	#define NODE_QLED  10   // qled read (no children)
21	#define NODE_QLED_ASSIGN 11  // qled <- expr (right = expr)
22	#define NODE_QSW   12   // qsw read (no children, read-only)
23	#define NODE_QSVO  13   // shared variable offer (val = sym index, right = AP expr)
24	#define NODE_SVO_READ  14   // shared var indexed read (val = sym index, right = index expr)
25	#define NODE_SVO_WRITE 15  // shared var indexed write (val = sym index, left = index, right = value)
26	#define NODE_GOTO  16   // unconditional branch (right = target expr)
27	#define NODE_CGOTO 17   // conditional branch (left = cond, right = target)
28	#define NODE_FNCALL 18  // user function call (val = fn index, left = left arg/-1, right = right arg)
29	
30	#define AST_MAX 64
31	
32	// AST storage (parallel arrays)
33	int node_type[AST_MAX];
34	int node_val[AST_MAX];
35	int node_left[AST_MAX];
36	int node_right[AST_MAX];
37	int node_count;
38	
39	// Parser state
40	int parse_pos;
41	int parse_err;
42	char *parse_line;   // source line for identifier lookup
43	
44	// Allocate a new AST node
45	int ast_new() {
46	    if (node_count >= AST_MAX) {
47	        parse_err = 1;
48	        return 0;
49	    }
50	    int n = node_count;
51	    node_count++;
52	    node_left[n] = -1;
53	    node_right[n] = -1;
54	    return n;
55	}
56	
57	int ast_num(int val) {
58	    int n = ast_new();
59	    node_type[n] = NODE_NUM;
60	    node_val[n] = val;
61	    return n;
62	}
63	
64	int ast_binop(int op, int left, int right) {
65	    int n = ast_new();
66	    node_type[n] = NODE_BINOP;
67	    node_val[n] = op;
68	    node_left[n] = left;
69	    node_right[n] = right;
70	    return n;
71	}
72	
73	int ast_neg(int operand) {
74	    int n = ast_new();
75	    node_type[n] = NODE_NEG;
76	    node_right[n] = operand;
77	    return n;
78	}
79	
80	int ast_ident(int sym_idx) {
81	    int n = ast_new();
82	    node_type[n] = NODE_IDENT;
83	    node_val[n] = sym_idx;
84	    return n;
85	}
86	
87	int ast_assign(int sym_idx, int expr) {
88	    int n = ast_new();
89	    node_type[n] = NODE_ASSIGN;
90	    node_val[n] = sym_idx;
91	    node_right[n] = expr;
92	    return n;
93	}
94	
95	int ast_vec(int heap_idx) {
96	    int n = ast_new();
97	    node_type[n] = NODE_VEC;
98	    node_val[n] = heap_idx;
99	    return n;
100	}
101	
102	int ast_monad(int res_id, int operand) {
103	    int n = ast_new();
104	    node_type[n] = NODE_MONAD;
105	    node_val[n] = res_id;
106	    node_right[n] = operand;
107	    return n;
108	}
109	
110	int ast_dyad(int res_id, int left, int right) {
111	    int n = ast_new();
112	    node_type[n] = NODE_DYAD;
113	    node_val[n] = res_id;
114	    node_left[n] = left;
115	    node_right[n] = right;
116	    return n;
117	}
118	
119	int ast_reduce(int op, int operand) {
120	    int n = ast_new();
121	    node_type[n] = NODE_REDUCE;
122	    node_val[n] = op;
123	    node_right[n] = operand;
124	    return n;
125	}
126	
127	// Check if a reserved word can be used dyadically
128	int is_dyadic_res(int res_id) {
129	    return res_id == RES_RHO || res_id == RES_TAKE || res_id == RES_DROP || res_id == RES_CAT || res_id == RES_AND || res_id == RES_OR || res_id == RES_CEIL || res_id == RES_FLOOR || res_id == RES_COMPRESS || res_id == RES_PICK;
130	}
131	
132	// Temporary buffer for collecting strand elements
133	int strand_buf[64];
134	
135	int is_binop(int ty) {
136	    return ty == TOK_PLUS || ty == TOK_MINUS || ty == TOK_STAR || ty == TOK_SLASH ||
137	           ty == TOK_EQ || ty == TOK_NE || ty == TOK_LT || ty == TOK_GT ||
138	           ty == TOK_LE || ty == TOK_GE;
139	}
140	
141	// Check if token at pos could start an expression (for function call detection)
142	int can_start_expr(int pos) {
143	    int ty = tok_type[pos];
144	    if (ty == TOK_NUM || ty == TOK_LPAREN || ty == TOK_IDENT ||
145	        ty == TOK_MINUS || ty == TOK_RES || ty == TOK_QLED || ty == TOK_QSW ||
146	        ty == TOK_STRING) return 1;
147	    if (is_binop(ty) && tok_type[pos + 1] == TOK_SLASH) return 1;  // reduce
148	    return 0;
149	}
150	
151	// Combined parse function avoids mutual recursion.
152	// mode 0 = expression, mode 1 = value only
153	int parse_node(int mode);
154	
155	int parse_node(int mode) {
156	    if (parse_err) return 0;
157	
158	    int left;
159	    int ty = tok_type[parse_pos];
160	
161	    // -- Parse a value --
162	
163	    if (ty == TOK_NUM) {
164	        left = ast_num(tok_val[parse_pos]);
165	        parse_pos++;
166	
167	        // Stranding: adjacent numbers form a vector (e.g. 1 2 3)
168	        if (tok_type[parse_pos] == TOK_NUM) {
169	            strand_buf[0] = node_val[left];
170	            int count = 1;
171	            while (tok_type[parse_pos] == TOK_NUM && count < 64) {
172	                strand_buf[count] = tok_val[parse_pos];
173	                parse_pos++;
174	                count++;
175	            }
176	            int aidx = arr_vector(count);
177	            if (aidx < 0) { parse_err = 1; return 0; }
178	            int si = 0;
179	            while (si < count) {
180	                arr_set(aidx, si, strand_buf[si]);
181	                si++;
182	            }
183	            left = ast_vec(aidx);
184	        }
185	    } else if (ty == TOK_LPAREN) {
186	        parse_pos++;
187	        left = parse_node(0);
188	        if (parse_err) return 0;
189	        if (tok_type[parse_pos] != TOK_RPAREN) {
190	            parse_err = 1;
191	            return 0;
192	        }
193	        parse_pos++;
194	    } else if (ty == TOK_QLED) {
195	        int n = ast_new();
196	        node_type[n] = NODE_QLED;
197	        left = n;
198	        parse_pos++;
199	    } else if (ty == TOK_QSW) {
200	        int n = ast_new();
201	        node_type[n] = NODE_QSW;
202	        left = n;
203	        parse_pos++;
204	    } else if (ty == TOK_STRING) {
205	        if (tok_type[parse_pos + 1] == TOK_QSVO) {
206	            // String as identifier for qsvo coupling: 'NAME' qsvo AP
207	            int sym_idx = sym_lookup(parse_line, tok_val[parse_pos]);
208	            if (sym_idx < 0) { parse_err = 1; return 0; }
209	            left = ast_ident(sym_idx);
210	            parse_pos++;
211	        } else {
212	            // Character vector literal: 'hello' -> char vector
213	            int start = tok_val[parse_pos];
214	            int end = start;
215	            while (parse_line[end] && parse_line[end] != 39) end++;
216	            int len = end - start;
217	            int aidx = arr_vector(len);
218	            if (aidx < 0) { parse_err = 1; return 0; }
219	            arr_set_type(aidx, ARR_CHAR);
220	            int ci = 0;
221	            while (ci < len) {
222	                arr_set(aidx, ci, parse_line[start + ci]);
223	                ci++;
224	            }
225	            parse_pos++;
226	
227	            // String stranding: adjacent strings form a boxed vector
228	            if (tok_type[parse_pos] == TOK_STRING) {
229	                strand_buf[0] = aidx;
230	                int count = 1;
231	                while (tok_type[parse_pos] == TOK_STRING && count < 64) {
232	                    int s2 = tok_val[parse_pos];
233	                    int e2 = s2;
234	                    while (parse_line[e2] && parse_line[e2] != 39) e2++;
235	                    int l2 = e2 - s2;
236	                    int a2 = arr_vector(l2);
237	                    if (a2 < 0) { parse_err = 1; return 0; }
238	                    arr_set_type(a2, ARR_CHAR);
239	                    int k = 0;
240	                    while (k < l2) {
241	                        arr_set(a2, k, parse_line[s2 + k]);
242	                        k++;
243	                    }
244	                    strand_buf[count] = a2;
245	                    parse_pos++;
246	                    count++;
247	                }
248	                // Create boxed vector holding heap indices
249	                int bidx = arr_vector(count);
250	                if (bidx < 0) { parse_err = 1; return 0; }
251	                arr_set_type(bidx, ARR_BOXED);
252	                int bi = 0;
253	                while (bi < count) {
254	                    arr_set(bidx, bi, strand_buf[bi]);
255	                    bi++;
256	                }
257	                left = ast_vec(bidx);
258	            } else {
259	                left = ast_vec(aidx);
260	            }
261	        }
262	    } else if (ty == TOK_IDENT) {
263	        int sym_idx = sym_lookup(parse_line, tok_val[parse_pos]);
264	        if (sym_idx < 0) { parse_err = 1; return 0; }
265	        parse_pos++;
266	        // Check for monadic function call
267	        int fi = fn_lookup(sym_idx);
268	        if (fi >= 0 && fn_left_sym[fi] < 0 && can_start_expr(parse_pos)) {
269	            // Monadic user function call: FN expr
270	            int arg = parse_node(0);
271	            if (parse_err) return 0;
272	            int nd = ast_new();
273	            node_type[nd] = NODE_FNCALL;
274	            node_val[nd] = fi;
275	            node_right[nd] = arg;
276	            left = nd;
277	        } else if (tok_type[parse_pos] == TOK_LBRAK) {
278	            // IDENT[expr] -- shared variable indexed read
279	            parse_pos++;
280	            int idx_expr = parse_node(0);
281	            if (parse_err) return 0;
282	            if (tok_type[parse_pos] != TOK_RBRAK) { parse_err = 1; return 0; }
283	            parse_pos++;
284	            int nd = ast_new();
285	            node_type[nd] = NODE_SVO_READ;
286	            node_val[nd] = sym_idx;
287	            node_right[nd] = idx_expr;
288	            left = nd;
289	        } else {
290	            left = ast_ident(sym_idx);
291	        }
292	    } else if (is_binop(ty) && tok_type[parse_pos + 1] == TOK_SLASH) {
293	        // Reduce operator: +/ -/ */ (op followed by slash)
294	        int op = ty;
295	        parse_pos = parse_pos + 2;
296	        int operand = parse_node(0);
297	        if (parse_err) return 0;
298	        left = ast_reduce(op, operand);
299	    } else if (ty == TOK_RES && (tok_val[parse_pos] == RES_CEIL || tok_val[parse_pos] == RES_FLOOR) && tok_type[parse_pos + 1] == TOK_SLASH) {
300	        // Reduce with ceil/ or floor/ (max-reduce, min-reduce)
301	        int op = (tok_val[parse_pos] == RES_CEIL) ? TOK_CEIL : TOK_FLOOR;
302	        parse_pos = parse_pos + 2;
303	        int operand = parse_node(0);
304	        if (parse_err) return 0;
305	        left = ast_reduce(op, operand);
306	    } else if (ty == TOK_RES) {
307	        // Monadic primitive function (e.g. iota expr)
308	        int res_id = tok_val[parse_pos];
309	        parse_pos++;
310	        int operand = parse_node(0);
311	        if (parse_err) return 0;
312	        left = ast_monad(res_id, operand);
313	    } else if (ty == TOK_MINUS) {
314	        // Monadic negate: applies to entire right expression (APL rule)
315	        parse_pos++;
316	        int operand = parse_node(0);
317	        if (parse_err) return 0;
318	        left = ast_neg(operand);
319	    } else {
320	        parse_err = 1;
321	        return 0;
322	    }
323	
324	    // -- If mode 0 (expr) and next is binop or dyadic reserved, parse right --
325	
326	    if (mode == 0 && is_binop(tok_type[parse_pos])) {
327	        int op = tok_type[parse_pos];
328	        parse_pos++;
329	        int right = parse_node(0);
330	        if (parse_err) return 0;
331	        return ast_binop(op, left, right);
332	    }
333	
334	    if (mode == 0 && tok_type[parse_pos] == TOK_RES && is_dyadic_res(tok_val[parse_pos])) {
335	        int res_id = tok_val[parse_pos];
336	        parse_pos++;
337	        int right = parse_node(0);
338	        if (parse_err) return 0;
339	        return ast_dyad(res_id, left, right);
340	    }
341	
342	    // Shared variable offer: 'NAME' qsvo EXPR  (or legacy: IDENT qsvo EXPR)
343	    if (mode == 0 && tok_type[parse_pos] == TOK_QSVO && node_type[left] == NODE_IDENT) {
344	        int sym_idx = node_val[left];
345	        parse_pos++;
346	        int right = parse_node(0);
347	        if (parse_err) return 0;
348	        int n = ast_new();
349	        node_type[n] = NODE_QSVO;
350	        node_val[n] = sym_idx;
351	        node_right[n] = right;
352	        return n;
353	    }
354	
355	    // Dyadic user function call: expr FN expr
356	    if (mode == 0 && tok_type[parse_pos] == TOK_IDENT) {
357	        int dsym = sym_lookup(parse_line, tok_val[parse_pos]);
358	        if (dsym >= 0) {
359	            int dfi = fn_lookup(dsym);
360	            if (dfi >= 0 && fn_left_sym[dfi] >= 0) {
361	                parse_pos++;
362	                int right = parse_node(0);
363	                if (parse_err) return 0;
364	                int nd = ast_new();
365	                node_type[nd] = NODE_FNCALL;
366	                node_val[nd] = dfi;
367	                node_left[nd] = left;
368	                node_right[nd] = right;
369	                return nd;
370	            }
371	        }
372	    }
373	
374	    return left;
375	}
376	
377	// Parse the token stream. Returns root node index, or -1 on error.
378	// line is needed for identifier name resolution into the symbol table.
379	int parse(char *line) {
380	    node_count = 0;
381	    parse_pos = 0;
382	    parse_err = 0;
383	    parse_line = line;
384	
385	    // Check for qled assignment: qled <- expr
386	    if (tok_type[0] == TOK_QLED && tok_type[1] == TOK_ASSIGN) {
387	        parse_pos = 2;
388	        int expr = parse_node(0);
389	        if (parse_err) return -1;
390	        if (tok_type[parse_pos] != TOK_EOL) return -1;
391	        int n = ast_new();
392	        node_type[n] = NODE_QLED_ASSIGN;
393	        node_right[n] = expr;
394	        return n;
395	    }
396	
397	    // Check for qsw assignment: qsw is read-only, reject with SYNTAX ERROR
398	    if (tok_type[0] == TOK_QSW && tok_type[1] == TOK_ASSIGN) {
399	        return -1;
400	    }
401	
402	    // Check for quad output: [] <- expr (IBM 5100 convention)
403	    if (tok_type[0] == TOK_QUAD && tok_type[1] == TOK_ASSIGN) {
404	        parse_pos = 2;
405	        int expr = parse_node(0);
406	        if (parse_err) return -1;
407	        if (tok_type[parse_pos] != TOK_EOL) return -1;
408	        int n = ast_new();
409	        node_type[n] = NODE_QOUT;
410	        node_right[n] = expr;
411	        return n;
412	    }
413	
414	    // Check for shared variable indexed write: IDENT[expr] <- expr
415	    if (tok_type[0] == TOK_IDENT && tok_type[1] == TOK_LBRAK) {
416	        int sym_idx = sym_lookup(line, tok_val[0]);
417	        if (sym_idx < 0) { return -1; }
418	        parse_pos = 2;
419	        int idx_expr = parse_node(0);
420	        if (parse_err) return -1;
421	        if (tok_type[parse_pos] != TOK_RBRAK) { parse_err = 1; return -1; }
422	        parse_pos++;
423	        if (tok_type[parse_pos] == TOK_ASSIGN) {
424	            // IDENT[expr] <- expr (indexed write)
425	            parse_pos++;
426	            int val_expr = parse_node(0);
427	            if (parse_err) return -1;
428	            if (tok_type[parse_pos] != TOK_EOL) return -1;
429	            int n = ast_new();
430	            node_type[n] = NODE_SVO_WRITE;
431	            node_val[n] = sym_idx;
432	            node_left[n] = idx_expr;
433	            node_right[n] = val_expr;
434	            return n;
435	        }
436	        if (tok_type[parse_pos] != TOK_EOL) {
437	            // IDENT[expr] followed by more (could be in expression context)
438	            // For now, only standalone read supported at top level
439	            // Fall through to expression parsing below
440	            parse_pos = 0;
441	            node_count = 0;
442	            parse_err = 0;
443	        } else {
444	            // IDENT[expr] standalone read
445	            int n = ast_new();
446	            node_type[n] = NODE_SVO_READ;
447	            node_val[n] = sym_idx;
448	            node_right[n] = idx_expr;
449	            return n;
450	        }
451	    }
452	
453	    // Check for goto: goto expr  or  goto (expr)/LABEL
454	    if (tok_type[0] == TOK_GOTO) {
455	        parse_pos = 1;
456	        if (tok_type[1] == TOK_LPAREN) {
457	            // Conditional: goto (expr)/TARGET
458	            parse_pos = 2;
459	            int cond = parse_node(0);
460	            if (parse_err) return -1;
461	            if (tok_type[parse_pos] != TOK_RPAREN) return -1;
462	            parse_pos++;
463	            if (tok_type[parse_pos] != TOK_SLASH) return -1;
464	            parse_pos++;
465	            int target = parse_node(0);
466	            if (parse_err) return -1;
467	            if (tok_type[parse_pos] != TOK_EOL) return -1;
468	            int n = ast_new();
469	            node_type[n] = NODE_CGOTO;
470	            node_left[n] = cond;
471	            node_right[n] = target;
472	            return n;
473	        }
474	        // Unconditional: goto expr
475	        int target = parse_node(0);
476	        if (parse_err) return -1;
477	        if (tok_type[parse_pos] != TOK_EOL) return -1;
478	        int n = ast_new();
479	        node_type[n] = NODE_GOTO;
480	        node_right[n] = target;
481	        return n;
482	    }
483	
484	    // Check for assignment: IDENT <- expr
485	    if (tok_type[0] == TOK_IDENT && tok_type[1] == TOK_ASSIGN) {
486	        int sym_idx = sym_lookup(line, tok_val[0]);
487	        if (sym_idx < 0) { return -1; }
488	        parse_pos = 2;
489	        int expr = parse_node(0);
490	        if (parse_err) return -1;
491	        if (tok_type[parse_pos] != TOK_EOL) return -1;
492	        return ast_assign(sym_idx, expr);
493	    }
494	
495	    int root = parse_node(0);
496	
497	    if (!parse_err && tok_type[parse_pos] != TOK_EOL) {
498	        parse_err = 1;
499	    }
500	
501	    if (parse_err) return -1;
502	    return root;
503	}
504	
505	// Debug: dump AST with full parenthesization
506	void ast_dump(int n) {
507	    if (n < 0 || n >= node_count) return;
508	
509	    int ty = node_type[n];
510	    if (ty == NODE_NUM) {
511	        print_int(node_val[n]);
512	    } else if (ty == NODE_BINOP) {
513	        putchar(40);
514	        ast_dump(node_left[n]);
515	        putchar(32);
516	        if (node_val[n] == TOK_PLUS)  putchar(43);
517	        if (node_val[n] == TOK_MINUS) putchar(45);
518	        if (node_val[n] == TOK_STAR)  putchar(42);
519	        if (node_val[n] == TOK_SLASH) putchar(47);
520	        putchar(32);
521	        ast_dump(node_right[n]);
522	        putchar(41);
523	    } else if (ty == NODE_NEG) {
524	        putchar(40);
525	        putchar(45);
526	        ast_dump(node_right[n]);
527	        putchar(41);
528	    }
529	}
