1	//! Bitwise operators. Assumes r0=lhs, r1=rhs already evaluated.
2	
3	use tc24r_codegen_state::CodegenState;
4	use tc24r_emit_macros::emit;
5	
6	/// Bitwise AND: r0 = r0 & r1.
7	pub fn gen_bitwise_and(state: &mut CodegenState) {
8	    emit!(state, "        and     r0,r1");
9	}
10	
